 1→import { useCallback, useState } from 'react';
 2→
 3→const STORAGE_KEY = 'raycast-favorites';
 4→
 5→function loadFavorites(): string[] {
 6→  try {
 7→    const stored = localStorage.getItem(STORAGE_KEY);
 8→    if (stored) {
 9→      const parsed: unknown = JSON.parse(stored);
10→      if (Array.isArray(parsed) && parsed.every(id => typeof id === 'string')) {
11→        return parsed;
12→      }
13→    }
14→  } catch {
15→    // ignore
16→  }
17→  return [];
18→}
19→
20→function saveFavorites(ids: string[]) {
21→  try {
22→    localStorage.setItem(STORAGE_KEY, JSON.stringify(ids));
23→  } catch {
24→    // ignore
25→  }
26→}
27→
28→export function useFavorites() {
29→  const [favoriteIds, setFavoriteIds] = useState<string[]>(loadFavorites);
30→
31→  const isFavorite = useCallback(
32→    (id: string) => favoriteIds.includes(id),
33→    [favoriteIds],
34→  );
35→
36→  const toggleFavorite = useCallback((id: string) => {
37→    setFavoriteIds(prev => {
38→      const next = prev.includes(id)
39→        ? prev.filter(fid => fid !== id)
40→        : [
41→            ...prev,
42→            id,
43→          ];
44→      saveFavorites(next);
45→      return next;
46→    });
47→  }, []);
48→
49→  const moveFavorite = useCallback((id: string, direction: 'up' | 'down') => {
50→    setFavoriteIds(prev => {
51→      const idx = prev.indexOf(id);
52→      if (idx === -1) return prev;
53→      const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
54→      if (targetIdx < 0 || targetIdx >= prev.length) return prev;
55→      const next = [...prev];
56→      next[idx] = prev[targetIdx]!;
57→      next[targetIdx] = prev[idx]!;
58→      saveFavorites(next);
59→      return next;
60→    });
61→  }, []);
62→
63→  return {
64→    favoriteIds,
65→    isFavorite,
66→    toggleFavorite,
67→    moveFavorite,
68→  };
69→}
