  54→function filterSections(sections: SectionData[], query: string): SectionData[] {
  55→  if (!query) return sections;
  56→  const lower = query.toLowerCase();
  57→  return sections
  58→    .map(section => ({
  59→      ...section,
  60→      items: section.items.filter(
  61→        item =>
  62→          item.title.toLowerCase().includes(lower) ||
  63→          item.subtitle?.toLowerCase().includes(lower),
  64→      ),
  65→    }))
  66→    .filter(section => section.items.length > 0);
  67→}
  68→
  69→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  70→  if (!query) return colors;
  71→  const lower = query.toLowerCase();
  72→  return colors.filter(
  73→    c =>
  74→      c.title.toLowerCase().includes(lower) ||
  75→      c.subtitle?.toLowerCase().includes(lower),
  76→  );
  77→}
  78→
  79→function flattenItems(sections: SectionData[]): ListItemData[] {
  80→  return sections.flatMap(s => s.items);
  81→}
